function StateExamples() {
  const [count, setCount] = useState(0);
  const [user, setUser] = useState({ name: '', age: 0 });
  const [items, setItems] = useState([]);

  // Primitive: direct replacement
  const increment = () => setCount(c => c + 1);

  // Object: spread to preserve other fields
  const updateName = (name) => setUser(u => ({ ...u, name }));

  // Array: spread or concat for immutable update
  const addItem = (item) => setItems(i => [...i, item]);

  return <div>...</div>;
}

function Parent() {
  const [count, setCount] = useState(0); // state owned here
  return (
    <div>
      <p>Parent count: {count}</p>
      <Child count={count} onIncrement={() => setCount(c => c + 1)} />
    </div>
  );
}
function Child({ count, onIncrement }) {
  // count is a prop here - read-only
  return <button onClick={onIncrement}>Child: {count}</button>;
}
